use std::thread;

let handle = thread::spawn(|| {
    println!("Hello from a thread!");
});
handle.join().unwrap();

let data = vec![1, 2, 3];
let handle = thread::spawn(move || {
    println!("{:?}", data);
});
handle.join().unwrap();
// data has been moved into the thread

let handle = thread::spawn(|| {
    42
});
let result = handle.join().unwrap();
assert_eq!(result, 42);

let builder = thread::Builder::new()
    .name("worker".into())
    .stack_size(4 * 1024 * 1024);
let handle = builder.spawn(|| {
    println!("thread: {:?}", thread::current().name());
}).unwrap();

let mut data = vec![1, 2, 3];
thread::scope(|s| {
    s.spawn(|| {
        println!("{:?}", data); // can borrow data
    });
    s.spawn(|| {
        println!("another thread");
    });
});
// all scoped threads joined here; data is still accessible

let cores = thread::available_parallelism()
    .map(|n| n.get())
    .unwrap_or(1);
println!("Available cores: {cores}");

use std::sync::mpsc;
let (tx, rx) = mpsc::channel();
thread::spawn(move || {
    tx.send("hello").unwrap();
});
let msg = rx.recv().unwrap();
println!("{msg}");

let (tx, rx) = mpsc::channel();
for i in 0..5 {
    let tx = tx.clone();
    thread::spawn(move || {
        tx.send(i).unwrap();
    });
}
drop(tx); // drop original sender
for received in rx {
    println!("{received}");
}

let (tx, rx) = mpsc::sync_channel(3); // buffer size 3
tx.send(1).unwrap(); // non-blocking while buffer not full
tx.send(2).unwrap();
tx.send(3).unwrap();
// tx.send(4) would block until rx.recv()

let (tx, rx) = mpsc::channel::<i32>();
match rx.try_recv() {
    Ok(msg) => println!("got: {msg}"),
    Err(mpsc::TryRecvError::Empty) => println!("no message yet"),
    Err(mpsc::TryRecvError::Disconnected) => println!("channel closed"),
}

use std::time::Duration;
let (tx, rx) = mpsc::channel::<i32>();
match rx.recv_timeout(Duration::from_secs(1)) {
    Ok(msg) => println!("{msg}"),
    Err(_) => println!("timed out"),
}

use std::sync::Mutex;
