use std::sync::{Arc, Mutex};
let data = Arc::new(Mutex::new(vec![]));
let handles: Vec<_> = (0..5).map(|i| {
    let data = Arc::clone(&data);
    thread::spawn(move || {
        data.lock().unwrap().push(i);
    })
}).collect();
for h in handles { h.join().unwrap(); }
println!("{:?}", data.lock().unwrap());

let m = Mutex::new(5);
let _ = thread::spawn(move || {
    let _lock = m.lock().unwrap();
    panic!("thread panicked while holding lock");
}).join();
// m is now poisoned; lock() returns Err
// Use into_inner() or clear_poison() to recover

let m = Mutex::new(42);
match m.try_lock() {
    Ok(guard) => println!("got lock: {}", *guard),
    Err(_) => println!("lock is held by another thread"),
}

use std::sync::RwLock;
let lock = RwLock::new(5);
{
    let r1 = lock.read().unwrap();
    let r2 = lock.read().unwrap();
    println!("{r1} {r2}"); // multiple readers OK
}
{
    let mut w = lock.write().unwrap();
    *w = 10; // exclusive write access
}

