use std::sync::atomic::{AtomicBool, Ordering};
let running = AtomicBool::new(true);
running.store(false, Ordering::SeqCst);
assert!(!running.load(Ordering::SeqCst));

use std::sync::atomic::{AtomicUsize, Ordering};
use std::sync::Arc;

let counter = Arc::new(AtomicUsize::new(0));
let handles: Vec<_> = (0..10).map(|_| {
    let counter = Arc::clone(&counter);
    thread::spawn(move || {
        counter.fetch_add(1, Ordering::SeqCst);
    })
}).collect();
for h in handles { h.join().unwrap(); }
println!("count: {}", counter.load(Ordering::SeqCst));

use std::sync::atomic::{AtomicI32, Ordering};
let val = AtomicI32::new(5);
let result = val.compare_exchange(
    5,    // expected
    10,   // new value
    Ordering::SeqCst,
    Ordering::SeqCst,
);
assert_eq!(result, Ok(5));

// Ordering::Relaxed   - no ordering guarantees
// Ordering::Acquire   - subsequent reads see writes before Release
// Ordering::Release   - previous writes visible to Acquire loads
// Ordering::AcqRel    - both Acquire and Release
// Ordering::SeqCst    - strictest; total ordering across all threads

// T: Send means T can be transferred to another thread
// Most types are Send
// Rc<T> is NOT Send (not thread-safe)
// Raw pointers are NOT Send

// T: Sync means &T can be shared across threads
// T is Sync if &T is Send
// Mutex<T> is Sync (provides synchronized access)
// RefCell<T> is NOT Sync (runtime borrow checking is not thread-safe)

// Send and Sync are auto-derived:
// A struct is Send if all fields are Send
// A struct is Sync if all fields are Sync

// Manually implement (unsafe):
unsafe impl Send for MyType {}
unsafe impl Sync for MyType {}

